import pymongo

def find_users_by_email(email):
    client = pymongo.MongoClient("mongodb://localhost:27017/")
    db = client["mydatabase"]
    users = db["users"]

    # Use the $regex operator to search for email addresses that match the provided string
    query = {"email": {"$regex": f"^{email}$", "$options": "i"}}

    # Use the find() method to execute the query and return a list of matching documents
    results = users.find(query)

    # Close the MongoDB client connection
    client.close()

    return [result["_id"] for result in results]